// // If A1 is low, X outputs high; if A1 is high and A2 is low, X outputs low; if both A1 and A2 are high but A3 is low, X outputs high; otherwise, X takes the value of B1.
module top_module(
    X ,
    A1,
    A2,
    A3,
    B1
);output X ;
    input  A1;
    input  A2;
    input  A3;
    input  B1;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign X = (A1) ? 1 :
                (A2) ? 0 :
                (A3) ? 1 :
                B1;

endmodule
